/* TrainingList.jsx */
import React, { useState, useMemo } from 'react';
import TrainingCard from '../components/TrainingCard';
import { trainings } from '../data/mockData';

const CATEGORIES = ['All', 'Development', 'Data Science', 'Design', 'DevOps', 'Marketing', 'Web3'];
const LEVELS     = ['All', 'Beginner', 'Intermediate', 'Advanced'];
const MAX_PRICE  = 8000;

export default function TrainingList() {
  const [filters, setFilters] = useState({
    category: 'All',
    level: 'All',
    maxPrice: MAX_PRICE,
    certificate: false,
    search: '',
  });
  const [sortBy, setSortBy] = useState('popular');

  const set = (key, value) => setFilters(f => ({ ...f, [key]: value }));

  const filtered = useMemo(() => {
    let result = trainings.filter(t => {
      if (filters.search && !t.title.toLowerCase().includes(filters.search.toLowerCase())
          && !t.provider.toLowerCase().includes(filters.search.toLowerCase())) return false;
      if (filters.category !== 'All' && t.category !== filters.category) return false;
      if (filters.level !== 'All' && t.level !== filters.level) return false;
      if (t.price > filters.maxPrice) return false;
      if (filters.certificate && !t.certificate) return false;
      return true;
    });

    if (sortBy === 'popular')    result = [...result].sort((a,b) => b.enrolled - a.enrolled);
    if (sortBy === 'rating')     result = [...result].sort((a,b) => b.rating - a.rating);
    if (sortBy === 'price-low')  result = [...result].sort((a,b) => a.price - b.price);
    if (sortBy === 'price-high') result = [...result].sort((a,b) => b.price - a.price);
    return result;
  }, [filters, sortBy]);

  const resetFilters = () => setFilters({
    category: 'All', level: 'All', maxPrice: MAX_PRICE, certificate: false, search: '',
  });

  return (
    <div className="tlist page-enter">
      {/* Header */}
      <div className="tlist__header">
        <div className="container">
          <div className="section-label">Upskill</div>
          <h1 className="tlist__title">Training Programs</h1>
          <p className="tlist__subtitle">400+ curated courses to accelerate your career trajectory.</p>

          <div className="tlist__search-wrap">
            <span className="tlist__search-icon">🔍</span>
            <input
              className="tlist__search"
              type="text"
              placeholder="Search courses, skills, or providers..."
              value={filters.search}
              onChange={e => set('search', e.target.value)}
            />
          </div>

          {/* Category Quick Tabs */}
          <div className="tlist__cat-tabs">
            {CATEGORIES.map(cat => (
              <button
                key={cat}
                className={`tlist__cat-tab ${filters.category === cat ? 'tlist__cat-tab--active' : ''}`}
                onClick={() => set('category', cat)}>
                {cat}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="container tlist__body">
        {/* SIDEBAR */}
        <aside className="tlist__sidebar">
          <div className="filter-panel">
            <div className="filter-panel__header">
              <span className="filter-panel__title">Refine</span>
              <button className="filter-panel__reset" onClick={resetFilters}>Reset</button>
            </div>

            {/* Level */}
            <div className="filter-group">
              <label className="filter-group__label">Level</label>
              <div className="filter-chips">
                {LEVELS.map(l => (
                  <button
                    key={l}
                    className={`filter-chip ${filters.level === l ? 'filter-chip--active' : ''}`}
                    onClick={() => set('level', l)}>
                    {l}
                  </button>
                ))}
              </div>
            </div>

            {/* Price */}
            <div className="filter-group">
              <label className="filter-group__label">
                Max Price: <strong style={{ color: 'var(--mint)' }}>₹{filters.maxPrice.toLocaleString()}</strong>
              </label>
              <input
                type="range"
                className="filter-range"
                min="0"
                max={MAX_PRICE}
                step="500"
                value={filters.maxPrice}
                onChange={e => set('maxPrice', Number(e.target.value))}
              />
              <div className="filter-range-labels">
                <span>Free</span>
                <span>₹{MAX_PRICE.toLocaleString()}</span>
              </div>
            </div>

            {/* Certificate Toggle */}
            <div className="filter-group">
              <label className="filter-group__label">Certificate</label>
              <button
                className={`filter-toggle ${filters.certificate ? 'filter-toggle--active' : ''}`}
                onClick={() => set('certificate', !filters.certificate)}>
                <span className="filter-toggle__dot"></span>
                Certificate included
              </button>
            </div>

            {/* Top Providers */}
            <div className="filter-group">
              <label className="filter-group__label">Top Providers</label>
              <div className="tlist__providers">
                {['CodeCraft Academy', 'Data Nexus', 'Designora', 'GrowthLab'].map(p => (
                  <div key={p} className="tlist__provider-pill">
                    <span className="tlist__provider-dot"></span>
                    <span>{p}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </aside>

        {/* MAIN */}
        <div className="tlist__main">
          {/* Results Bar */}
          <div className="tlist__results-bar">
            <span className="tlist__results-count">
              <strong style={{ color: 'var(--text-primary)' }}>{filtered.length}</strong>
              <span style={{ color: 'var(--text-muted)' }}> courses available</span>
            </span>
            <div className="tlist__sort">
              <label className="filter-group__label" style={{ margin: 0 }}>Sort:</label>
              <select
                className="form-select tlist__sort-select"
                value={sortBy}
                onChange={e => setSortBy(e.target.value)}>
                <option value="popular">Most Popular</option>
                <option value="rating">Highest Rated</option>
                <option value="price-low">Price: Low to High</option>
                <option value="price-high">Price: High to Low</option>
              </select>
            </div>
          </div>

          {filtered.length > 0 ? (
            <div className="tlist__grid">
              {filtered.map(t => <TrainingCard key={t.id} training={t} />)}
            </div>
          ) : (
            <div className="tlist__empty">
              <span className="tlist__empty-icon">📚</span>
              <h3>No courses found</h3>
              <p>Try adjusting your search or filters.</p>
              <button className="btn btn-primary" onClick={resetFilters}>Reset Filters</button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
